class Solution {
    public List<String> removeInvalidParentheses(String s) {
        List<String> result = new ArrayList<>();
        Stack<Character> stack = new Stack<>();

        for (char c : s.toCharArray()) {
            if (c == '(') {
                stack.push(c);
            } else if (c == ')') {
                if (stack.isEmpty()) {
                    continue;
                }
                char top = stack.pop();
                if (top != '(') {
                    continue;
                }
            }
            result.add(s.substring(0, i) + top + s.substring(i));
        }
        return result;
    }
}
```

